module.exports = {
  ci: {
    collect: {
      startServerCommand: 'npx serve dist/client -l 4321',
      startServerReadyPattern: 'Accepting connections',
      url: [
        'http://localhost:4321/',
        'http://localhost:4321/about/',
        'http://localhost:4321/sermons/',
        'http://localhost:4321/contact/',
        'http://localhost:4321/events/',
        'http://localhost:4321/visit/',
        'http://localhost:4321/give/',
        'http://localhost:4321/zh/',
        'http://localhost:4321/styleguide/',
        'http://localhost:4321/404.html',
      ],
      numberOfRuns: 3,
    },
    assert: {
      assertMatrix: [
        // CJK pages: font subsetting generates ~240KB CSS (K001), scores ~0.55 under 4G throttle
        {
          matchingUrlPattern: '.*/zh(/.*)?$',
          assertions: {
            'categories:performance': ['warn', { minScore: 0.5 }],
            'categories:accessibility': ['error', { minScore: 0.95 }],
            'categories:seo': ['error', { minScore: 0.95 }],
            'categories:best-practices': ['error', { minScore: 0.9 }],
          },
        },
        // Styleguide: dev-only page, heavy CJK rendering
        {
          matchingUrlPattern: '.*/styleguide/.*',
          assertions: {
            'categories:performance': ['warn', { minScore: 0.5 }],
            'categories:accessibility': ['error', { minScore: 0.95 }],
            'categories:seo': ['error', { minScore: 0.95 }],
            'categories:best-practices': ['error', { minScore: 0.9 }],
          },

import { defineConfig } from 'astro/config';
import sitemap from '@astrojs/sitemap';
import sanity from '@sanity/astro';
import react from '@astrojs/react';
import vercel from '@astrojs/vercel';

export default defineConfig({
  site: 'https://ficcc.org',
  // Astro 5 removed output:'hybrid' — static + adapter is the equivalent,
  // enabling per-page SSR opt-in via `export const prerender = false`.
  output: 'static', // hybrid equivalent with adapter
  adapter: vercel(),
  integrations: [
    sitemap({
      i18n: {
        defaultLocale: 'en',
        locales: {
          en: 'en',
          zh: 'zh',
        },
      },
    }),
    sanity({
      projectId: import.meta.env.SANITY_PROJECT_ID || 'placeholder',
      dataset: import.meta.env.SANITY_DATASET || 'production',
      useCdn: false, // false for static builds per @sanity/astro docs
      stega: {
        studioUrl: import.meta.env.PUBLIC_SANITY_PREVIEW_URL || 'http://localhost:3333',
      },
    }),
    react(),
  ],
  i18n: {
    defaultLocale: 'en',
    locales: ['en', 'zh'],
    routing: {
      prefixDefaultLocale: false,
    },
  },
});

